// tailwind.config.ts (v3)
import type { Config } from "tailwindcss"
import defaultTheme from "tailwindcss/defaultTheme"

export default {
  content: [
    "./src/**/*.{ts,tsx,js,jsx,mdx}",
    "./components/**/*.{ts,tsx}",
    "./app/**/*.{ts,tsx}",
  ],
  darkMode: "class",
  theme: {
    extend: {
      colors: {
        background: "hsl(var(--background))",
        foreground: "hsl(var(--foreground))",
        primary: {
          DEFAULT: "hsl(var(--primary))",
          foreground: "hsl(var(--primary-foreground))",
        },
        brand: {
          50: "#eff6ff",
          500: "#3b82f6",
          900: "#1e3a8a",
        },
      },
      fontFamily: {
        sans: ["Inter var", ...defaultTheme.fontFamily.sans],
      },
    },
  },
  plugins: [
    require("@tailwindcss/forms"),
    require("@tailwindcss/typography"),
  ],
} satisfies Config

/* src/styles/globals.css (v4) */
@import "tailwindcss";

@theme {
  --color-brand-50: hsl(214 100% 97%);
  --color-brand-500: hsl(217 91% 60%);
  --color-brand-900: hsl(224 64% 33%);
  --font-sans: "Inter", system-ui, sans-serif;
  --radius-md: 0.5rem;
  --radius-lg: 0.75rem;
}

/* Dark mode via class strategy */
@layer base {
  :root { color-scheme: light; }
  .dark { color-scheme: dark; }
}

// Container
<div className="mx-auto max-w-7xl px-4 sm:px-6 lg:px-8">

// Responsive card grid (mobile-first)
<div className="grid grid-cols-1 gap-4 sm:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4">

// Stack (vertical flex with gap)
<div className="flex flex-col gap-4">

// Center (absolute centering)
<div className="flex items-center justify-center min-h-screen">

// Responsive flex → column on mobile, row on desktop
<div className="flex flex-col gap-2 md:flex-row md:items-center md:gap-4">

// Prose (with typography plugin)
<article className="prose prose-slate max-w-none dark:prose-invert">

// ThemeProvider wrapping the app
function ThemeProvider({ children }: { children: React.ReactNode }) {
  const [theme, setTheme] = useState<"light" | "dark">(() =>
    window.matchMedia("(prefers-color-scheme: dark)").matches ? "dark" : "light"
  )

  useEffect(() => {
    document.documentElement.classList.toggle("dark", theme === "dark")
  }, [theme])

  return (
    <ThemeContext.Provider value={{ theme, setTheme }}>
      {children}
    </ThemeContext.Provider>
  )
}
